package be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst;

import be.schaubroeck.lpb.rkm.rekenmotor.AbstractRekenCommand;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.TussenkomstManager;
import be.schaubroeck.lpb.rkm.rekenmotor.results.RekenResultatenBeheer;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.SleutelTussenkomstBedrag;
import be.schaubroeck.lpb.tools.SleutelTussenkomstHoofd;
import be.schaubroeck.lpb.tools.SleutelTussenkomstLijn;
import be.schaubroeck.lpb.tools.enumtypes.ManueleTussenkomstBron;
import be.schaubroeck.lpb.tools.enumtypes.OpslaanNulResultaten;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.jpa.lo.SleutelTussenkomstBedragPO;
import be.schaubroeck.lpb.tools.jpa.lo.SleutelTussenkomstHoofdPO;
import be.schaubroeck.lpb.tools.jpa.lo.SleutelTussenkomstLijnPO;
import com.google.common.collect.ImmutableSet;

import java.util.Collection;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.ACTOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SLEUTEL_TUSSENKOMSTEN;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.TUSSENKOMST_MANAGER_KEY;

public class GenereerNeutraliserendeSleutelTussenkomst extends AbstractRekenCommand {

    private Set<RekenBedragType> bedragTypes;

    public GenereerNeutraliserendeSleutelTussenkomst(Set<RekenBedragType> bedragTypes) {
        this.bedragTypes = ImmutableSet.copyOf(bedragTypes);
    }

    public GenereerNeutraliserendeSleutelTussenkomst() {
        this.bedragTypes = ImmutableSet.of();
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        String actor = mainContext.getUnchecked(ACTOR_KEY);
        List<RekenHoofd> outputs = vormNieuweRekenHoofden(mainContext);

        TussenkomstManager tussenkomstManager = mainContext.getUnchecked(TUSSENKOMST_MANAGER_KEY);
        for (RekenHoofd rekenHoofd : outputs) {
            SleutelTussenkomstHoofd hoofd = maakSleutelTussenkomstHoofd(rekenHoofd, actor);
            for (RekenLijn rekenLijn : rekenHoofd.getRekenLijnen()) {
                SleutelTussenkomstLijn lijn = maakSleutelTussenkomstLijn(rekenLijn, actor);
                lijn.setHoofd(hoofd);
                vormSleutelTussenkomstBedragen(lijn, rekenLijn.getRekenBedragen(), actor);
                hoofd.addLijn(lijn);
            }
            tussenkomstManager.addSleutelTussenkomst(hoofd);
        }
        return CONTINUE_PROCESSING;
    }

    protected List<RekenHoofd> vormNieuweRekenHoofden(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        List<RekenHoofd> bestaanden = persoonsDataManager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
        List<RekenHoofd> gelockten = bestaanden.stream().filter(t -> t.getRnummer() != null).collect(Collectors.toList());
        List<RekenHoofd> sleutelTussenkomsten = mainContext.getUnchecked(SLEUTEL_TUSSENKOMSTEN);
        if (sleutelTussenkomsten != null) {
            gelockten.addAll(sleutelTussenkomsten);
        }
        RekenResultatenBeheer rekenResultatenBeheer = new RekenResultatenBeheer();
        return rekenResultatenBeheer.maakRekenResultaten(mainContext, gelockten, OpslaanNulResultaten.NIET_OPSLAAN);
    }

    private SleutelTussenkomstHoofd maakSleutelTussenkomstHoofd(RekenHoofd rekenHoofd, String actor) {
        SleutelTussenkomstHoofd hoofd = new SleutelTussenkomstHoofdPO();
        hoofd.setOpdracht(rekenHoofd.getOpdracht());
        hoofd.setBeginDatum(rekenHoofd.getBeginDatum());
        hoofd.setEindDatum(rekenHoofd.getEindDatum());
        hoofd.setBeslagDatum(rekenHoofd.getBeslagDatum());
        hoofd.setHoedanigheid(rekenHoofd.getHoedanigheid());
        hoofd.setCategorie(rekenHoofd.getCategorie());
        hoofd.setWerkgeversCategorie(rekenHoofd.getWerkgeversCategorie());
        hoofd.setWerknemersKengetal(rekenHoofd.getWerknemersKengetal());
        hoofd.setPensioenStelsel(rekenHoofd.getPensioenStelsel());
        hoofd.setVerantwoording("");
        hoofd.setBron(ManueleTussenkomstBron.NEUTRALISATIE);
        hoofd.setActor(actor);
        return hoofd;
    }

    private SleutelTussenkomstLijn maakSleutelTussenkomstLijn(RekenLijn rekenLijn, String actor) {
        SleutelTussenkomstLijn lijn = new SleutelTussenkomstLijnPO();
        lijn.setBeginDatum(rekenLijn.getBeginDatum());
        lijn.setEindDatum(rekenLijn.getEindDatum());
        lijn.setAardKodeExtensie(rekenLijn.getAardKodeExtensie());
        lijn.setRegimeBv(rekenLijn.getRegimeBv());
        lijn.setReferentieJaar(rekenLijn.getReferentieJaar());
        lijn.setActor(actor);
        return lijn;
    }

    private SleutelTussenkomstBedrag maakSleutelTussenkomstBedrag(RekenBedrag rekenBedrag, String actor) {
        SleutelTussenkomstBedrag sleutelTussenkomstBedrag = new SleutelTussenkomstBedragPO();
        sleutelTussenkomstBedrag.setBedragType(rekenBedrag.getBedragType());
        sleutelTussenkomstBedrag.setBedrag(rekenBedrag.getBedrag());
        sleutelTussenkomstBedrag.setActor(actor);
        return sleutelTussenkomstBedrag;
    }

    private void vormSleutelTussenkomstBedragen(SleutelTussenkomstLijn lijn, Collection<RekenBedrag> rekenBedragen, String actor) {
        for (RekenBedrag rekenBedrag : rekenBedragen) {
            if (bedragTypes.isEmpty() || bedragTypes.contains(rekenBedrag.getBedragType())) {
                SleutelTussenkomstBedrag sleutelTussenkomstBedrag = maakSleutelTussenkomstBedrag(rekenBedrag, actor);
                sleutelTussenkomstBedrag.setLijn(lijn);
                lijn.addBedrag(sleutelTussenkomstBedrag);
            }

        }
    }

}
